checker_dsl:
AND {
  EXISTS (`if-statement IF1`) {
    EXISTS (`synchronized statement SYNC`) {
      (`IF1's then-block contains SYNC`)
    }
  },
  EXISTS (`synchronized statement SYNC`) {
    EXISTS (`if-statement IF2`) {
      (`SYNC's block contains IF2`)
    }
  },
  EXISTS (`equality test EQ1`) {
    AND {
      (`EQ1 is the condition of IF1`),
      (`EQ1 has polarity true`),
      EXISTS (`null literal NL`) {
        EXISTS (`field read FR1`) {
          AND {
            (`EQ1 compares NL with a read of field F`),
            OR {
              (`FR1 is a direct access to field F`),
              EXISTS (`SSA explicit write V`) {
                AND {
                  (`V's source variable is a local scope variable`),
                  (`FR1 is a read from V`),
                  (`V's value is a field read of F`)
                }
              },
              (`FR1 is the source of an assignment expression that reads field F`)
            }
          }
        }
      }
    }
  },
  EXISTS (`equality test EQ2`) {
    AND {
      (`EQ2 is the condition of IF2`),
      (`EQ2 has polarity true`),
      EXISTS (`null literal NL2`) {
        EXISTS (`field read FR2`) {
          AND {
            (`EQ2 compares NL2 with a read of field F`),
            OR {
              (`FR2 is a direct access to field F`),
              EXISTS (`SSA explicit write V2`) {
                AND {
                  (`V2's source variable is a local scope variable`),
                  (`FR2 is a read from V2`),
                  (`V2's value is a field read of F`)
                }
              },
              (`FR2 is the source of an assignment expression that reads field F`)
            }
          }
        }
      }
    }
  },
  EXISTS (`assignment expression A`) {
    AND {
      (`A is contained in IF2's then-block and A's destination is a field access to field F`),
      EXISTS (`field F`) { (`true`) }
    }
  },
  EXISTS (`side-effect expression SE`) {
    AND {
      (`SE is contained in SYNC's block`),
      OR {
        AND {
          (`SE is a method call`),
          NOT {
            EXISTS (`method M`) {
              AND {
                (`M is the method of SE`),
                (`M's declaring type is in package java.io`),
                (`M's name is "println"`)
              }
            }
          }
        },
        (`SE is an assignment whose destination is a field access`)
      }
    }
  },
  EXISTS (`control flow node CFN`) {
    AND {
      (`CFN is the control flow node of A`),
      (`SE is reachable from CFN via one or more control flow successors`)
    }
  }
}
